"""Production HTTP guard service (Business tier — requires enterprise_http license)."""

from __future__ import annotations

import os
import time
from typing import Any

from pydantic import BaseModel, Field

from prismguard.licensing.features import ENTERPRISE_HTTP, require_feature
from prismguard.observability.metrics import get_metrics
from prismguard.runtime.check import RuntimeChecker
from prismguard.runtime.output_scan import scan_output
from prismguard.seed import import_bundled_seed, load_bundled_seed
from prismguard.storage import create_storage_from_env


class CheckRequest(BaseModel):
    text: str = Field(..., min_length=1, max_length=32_000)
    session_id: str | None = None


class CheckResponse(BaseModel):
    decision: str
    resolution_gate: str
    matched_category: str | None = None
    normalized_prompt: str = ""
    details: dict[str, Any] = Field(default_factory=dict)
    latency_ms: float = 0.0


class ScanOutputRequest(BaseModel):
    text: str = Field(..., min_length=1, max_length=128_000)


class ScanOutputResponse(BaseModel):
    decision: str
    resolution_gate: str
    matched_pattern: str | None = None
    details: dict[str, Any] = Field(default_factory=dict)
    latency_ms: float = 0.0


class HealthResponse(BaseModel):
    status: str
    ready: bool
    domain: str
    classifier_ready: bool


_checker: RuntimeChecker | None = None


def _get_checker() -> RuntimeChecker:
    global _checker
    if _checker is not None:
        return _checker
    domain = os.environ.get("PRISMGUARD_DOMAIN", "law")
    storage = create_storage_from_env()
    parsed = load_bundled_seed(profile=os.environ.get("PRISMGUARD_SEED_PROFILE", "authored"))
    import_bundled_seed(storage, profile=os.environ.get("PRISMGUARD_SEED_PROFILE", "authored"))
    from prismguard.config.loader import load_triage_config
    from prismguard.runtime.guard_model import create_guard_model
    from prismguard.runtime.llm_judge import create_llm_judge
    from prismguard.taxonomy.embedder import create_embedder_from_config

    cfg = load_triage_config(domain=domain)
    embedder = create_embedder_from_config(cfg)
    guard_model = create_guard_model(cfg.guard_model) if cfg.guard_model.enabled else None
    llm_judge = None
    if cfg.gray_zone_policy == "escalate" and guard_model is not None:
        llm_judge = create_llm_judge(
            prefer_openai=False,
            rate_cap_per_minute=cfg.judge.rate_cap_per_minute,
            embedder=embedder,
            cache_similarity_threshold=cfg.cache.semantic_cache_threshold,
        )
    _checker = RuntimeChecker.from_storage(
        storage,
        parsed,
        embedder=embedder,
        config=cfg,
        guard_model=guard_model,
        llm_judge=llm_judge,
    )
    return _checker


def create_app():
    """FastAPI app factory — lazy-imports fastapi so OSS installs stay light."""
    require_feature(ENTERPRISE_HTTP)
    from fastapi import FastAPI
    from starlette.concurrency import run_in_threadpool

    app = FastAPI(
        title="PrismGuard API",
        version="0.1.2",
        description="Audited prompt-injection guard service (Business tier).",
    )

    @app.on_event("startup")
    def _warm() -> None:
        _get_checker()

    @app.get("/health", response_model=HealthResponse)
    def health() -> HealthResponse:
        domain = os.environ.get("PRISMGUARD_DOMAIN", "law")
        try:
            checker = _get_checker()
            ready = checker._guard_model is None or checker._guard_model.is_ready  # noqa: SLF001
        except Exception:
            ready = False
        return HealthResponse(
            status="ok",
            ready=ready,
            domain=domain,
            classifier_ready=ready,
        )

    @app.get("/ready")
    def ready() -> dict[str, bool]:
        h = health()
        return {"ready": h.ready}

    @app.get("/metrics")
    def metrics() -> Any:
        from fastapi.responses import PlainTextResponse

        return PlainTextResponse(get_metrics().prometheus_text(), media_type="text/plain; version=0.0.4")

    @app.post("/v1/check", response_model=CheckResponse)
    async def check_input(req: CheckRequest) -> CheckResponse:
        start = time.perf_counter()
        metrics = get_metrics()
        try:
            checker = _get_checker()
            result = await run_in_threadpool(checker.check, req.text, session_id=req.session_id)
            metrics.record_check(decision=result.decision, gate=result.resolution_gate)
        except Exception:
            metrics.record_error()
            raise
        return CheckResponse(
            decision=result.decision,
            resolution_gate=result.resolution_gate,
            matched_category=result.matched_category,
            normalized_prompt=result.normalized_prompt,
            details=result.details,
            latency_ms=(time.perf_counter() - start) * 1000,
        )

    @app.post("/v1/scan-output", response_model=ScanOutputResponse)
    async def scan_output_endpoint(req: ScanOutputRequest) -> ScanOutputResponse:
        start = time.perf_counter()
        metrics = get_metrics()
        try:
            scan = await run_in_threadpool(scan_output, req.text)
            metrics.record_scan()
        except Exception:
            metrics.record_error()
            raise
        return ScanOutputResponse(
            decision=scan.decision,
            resolution_gate=scan.resolution_gate,
            matched_pattern=scan.matched_pattern,
            details=scan.details,
            latency_ms=(time.perf_counter() - start) * 1000,
        )

    return app


def main() -> None:
    import uvicorn

    host = os.environ.get("PRISMGUARD_HOST", "0.0.0.0")
    port = int(os.environ.get("PRISMGUARD_PORT", "8090"))
    uvicorn.run("prismguard.http.service:create_app", factory=True, host=host, port=port)


if __name__ == "__main__":
    main()
